import os, base64

root = os.path.join(os.path.expanduser("~"), "Desktop", "SkillScore")

App_vue = base64.b64decode('').decode("utf-8")
AnalyzeView_vue = base64.b64decode('').decode("utf-8")
ArchiveView_vue = base64.b64decode('').decode("utf-8")

deployments = {
    'src/App.vue': App_vue,
    'src/views/AnalyzeView.vue': AnalyzeView_vue,
    'src/views/ArchiveView.vue': ArchiveView_vue,
}

for rel, content in deployments.items():
    path = os.path.join(root, rel.replace("/", os.sep))
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f: f.write(content)
    print(f"Written: {rel}")
print("Done!")